(() => {
  const rawText = $items('Code2_b24', 0, 0)?.[0]?.json?.message?.text ?? '';
  const qaMdRaw = $items('Code_Conversation_b24', 0, 0)?.[0]?.json?.qa_md ?? '';

  let userQuery = '';
  let contextMsg = '';
  let parsed = null;

  try {
    parsed = JSON.parse(rawText);
    userQuery  = String(parsed.user_query ?? '').trim();
    contextMsg = String(parsed.context_message ?? '').trim();
  } catch (_) {}

  const qaMd = String(qaMdRaw ?? '').trim();
  if (!userQuery) {
    const matches = [...qaMd.matchAll(/\*\*Вопрос\s*\d*\s*\([^)]+\):\s*([\s\S]*?)(?=\n\*\*Ответ|\n\*\*Вопрос|\s*$)/g)];
    const lastQ = matches.at(-1)?.[1]?.trim();
    if (lastQ) userQuery = lastQ;
  }

  let linkInfoBlock = '';

  if (parsed && typeof parsed === 'object') {
    if (parsed.platform === 'avito' && parsed.avito && typeof parsed.avito === 'object') {
      const infoParts = [];
      if (parsed.avito.title) infoParts.push(`- Название: ${parsed.avito.title}`);
      if (parsed.avito.about_phone && typeof parsed.avito.about_phone === 'object') {
        const translations = { condition: 'Общее состояние', screen: 'Экран', body: 'Корпус', battery: 'Аккумулятор' };
        for (const [key, value] of Object.entries(parsed.avito.about_phone)) {
          if (value) infoParts.push(`- ${translations[key] || key}: ${value}`);
        }
      }
      if (infoParts.length > 0) {
        linkInfoBlock = `Ссылка клиента (Авито):\n${infoParts.join('\n')}`;
      }
    }

    if (!linkInfoBlock) {
      const tgText = String(parsed.telegram_text ?? parsed.link_text ?? '').trim();
      if (tgText) linkInfoBlock = `Ссылка клиента из Телеграм:\n"${tgText}"`;
    }

    if (!linkInfoBlock) {
      const nameMeta = String(parsed.name_meta ?? parsed.link_title ?? '').trim();
      if (nameMeta) linkInfoBlock = `Ссылка клиента:\n- Название: ${nameMeta}`;
    }
  }

  const MAX_CONTEXT_CHARS = 2500;
  const contextTrimmed = qaMd.length > MAX_CONTEXT_CHARS
    ? qaMd.slice(-MAX_CONTEXT_CHARS)
    : qaMd;

  const parts = [];

  if (contextTrimmed) {
    parts.push(`[КОНТЕКСТ ДИАЛОГА]\n${contextTrimmed}`);
  }

  const originalUserText = [userQuery, contextMsg].filter(Boolean).join('\n\n');
  let finalQueryBlock = '';

  if (linkInfoBlock) {
    const textClientBlock = `Текст клиента:\n${originalUserText}`;
    finalQueryBlock = [linkInfoBlock, textClientBlock].join('\n\n');
  } else {
    finalQueryBlock = originalUserText;
  }

  parts.push(
`[ЗАПРОС КЛИЕНТА — ОТВЕТЬ ИМЕННО НА ЭТО]
${finalQueryBlock || '(нет явного запроса — используй последний вопрос клиента из контекста)'}`
  );

  return parts.join('\n\n');
})()
}}

