      "ASUS": ["ASUS", "асус", "ROG", "ZenBook", "VivoBook", "TUF"],
      "Acer": ["Acer", "эйсер", "Aspire", "Nitro", "Swift", "Predator"],
      "Lenovo": ["Lenovo", "леново", "ThinkPad", "Legion", "LOQ", "Yoga", "Lenovo Tab"],
      "HP": ["HP", "эйчпи", "Pavilion", "Omen", "Victus"],
      "MSI": ["MSI", "эмэсай", "Katana", "Stealth", "Raider"],
      "DJI": ["DJI", "диджиай", "Mavic", "Air", "Mini", "Avata", "Osmo"],
      "GoPro": ["GoPro", "гоупро", "Hero"],
      "Insta360": ["Insta360", "инста360", "X", "Ace", "GO", "Flow"],
      "JBL": ["JBL", "джибиэл", "Flip", "Charge", "Tune", "Live", "Extreme"],
      "Beats": ["Beats", "битс", "Studio", "Fit Pro", "Solo", "Powerbeats"],
      "Bose": ["Bose", "боуз", "QC", "Ultra", "Sport Earbuds"],
      "Nintendo": ["Nintendo", "нинтендо", "Switch", "OLED", "Lite"],
      "Microsoft": ["Microsoft", "майкрософт", "Xbox", "Series X", "Series S"],
      "PlayStation": ["пска", "ПС", "ПС5", "ps vr", "плойка", "ps 5 slim", "ps без дисковода", "ps slim", "пс слим", "пс 5 слим", "Ps 5", "ps", "PS Plus", "пс плюс"],
      "Яндекс": ["Дуо", "станция", "Дуо Макс", "Станция мини", "миди", "Макс Дуо"],
      "Dreame": ["dreamy", "дрими", "дреами", "dreamee", "dreme"]
    },
    categories: {
      smartphone: ["смартфон", "телефон", "мобила", "iphone", "galaxy", "xiaomi", "redmi", "poco", "pixel", "xperia", "honor", "Про Макс"],
      tablet: ["планшет", "ipad", "tab", "matepad"],
      smartwatch: ["смартчасы", "умные часы", "часы", "watch", "band", "браслет"],
      earbuds: ["tws", "вкладыши", "airpods", "buds", "ear", "freebuds"],
      headphones: ["наушники", "гарнитура", "накладные", "полноразмерные", "720BT"],
      laptop: ["ноут", "ноутбук", "лэптоп", "macbook"],
      console: ["приставка", "консоль", "playstation", "ps", "xbox", "nintendo", "switch", "плойка", "пська", "ПС5", "икс бокс"],
      speaker: ["колонка", "портативная колонка", "bluetooth колонка", "спикер"]
    },
    typos: {
      "ксиоми": "Xiaomi", "сяоми": "Xiaomi", "самса": "Samsung", "эпл": "Apple",
      "хуавей": "Huawei", "виво": "vivo", "нотинг": "Nothing", "поко": "Xiaomi",
      "сони": "Sony", "логитек": "Logitech", "ps5": "PlayStation 5", "пс5": "PlayStation 5"
    }
  };

  if (!rawText) {
    return { type: "normalize", normalized_query: "", brands: [], categories: [], tokens: {}, intent_hint: "menu", confidence: 0.1 };
  }

  let text = rawText.toLowerCase().trim();
  let foundBrands = [];
  let foundCategories = [];
  let tokens = {};

  const storageValues = [];
  const storageRegex = /\b(32|64|128|256|512|1024)\s*(gb|гб)?\b/gi;
  text = text.replace(storageRegex, (m, size) => {
    const n = Number(size);
    if (!storageValues.includes(n)) storageValues.push(n);
    return " ";
  });
  if (storageValues.length) tokens.storage_gb = storageValues;

  for (const typo in lexicon.typos) {
    if (text.includes(typo)) {
      const safeTypo = typo.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      text = text.replace(new RegExp(`\\b${safeTypo}\\b`, 'g'), lexicon.typos[typo].toLowerCase());
    }
  }

  for (const brand in lexicon.brands) {
    for (const alias of lexicon.brands[brand]) {
      if (alias.length > 3 && new RegExp('\\b' + alias.replace(/[.*+?^${}()|[\]\\]/g, '\\$&') + '\\b', 'i').test(text)) {
        if (!foundBrands.includes(brand)) { foundBrands.push(brand); break; }
      }
    }
  }

  for (const category in lexicon.categories) {
    for (const keyword of lexicon.categories[category]) {
      if (text.includes(keyword.toLowerCase())) {
        if (!foundCategories.includes(category)) foundCategories.push(category);
      }
    }
  }

  const serviceWords = /\b(модели|модель|линейка|смартфон(ы)?|покажи(те)?|есть|в наличии|цена|стоимост[ьи]|сколько стоит|поч[её]м|купить|заказать|или)\b/gi;
  let normalizedQuery = text.replace(serviceWords, ' ').trim().replace(/\s+/g, ' ');

  let intentHint = "stock_list";
  if (/какие (есть )?модели/.test(text) || /линейка/.test(text)) intentHint = "models";
  else if (/сравни/.test(text) || text.split(/ vs | или | и /).length > 1) intentHint = "comparison";
  else if (/характеристики|параметры|подробно/.test(text)) intentHint = "results";

  if (foundBrands.includes("Samsung")) {
    normalizedQuery = normalizedQuery.replace(/\b(samsung|самсунг|самса)\b/gi, ' ').trim();
    if (!/galaxy/i.test(normalizedQuery)) normalizedQuery = ("Galaxy " + normalizedQuery).trim();
  }

  normalizedQuery = normalizedQuery.replace(/(\d)\s*\+/gi, '$1 Plus');
  normalizedQuery = normalizedQuery.replace(/\b(или|и|vs)\s*$/i, '').trim().replace(/\s+/g, ' ');

  return {
    type: "normalize",
    normalized_query: normalizedQuery,
    brands: foundBrands,
    categories: foundCategories,
    tokens,
    intent_hint: intentHint,
    confidence: (foundBrands.length > 0 || foundCategories.length > 0) ? 0.9 : 0.3
  };
}

const userQuery = query || '';
const result = normalize(userQuery);
return JSON.stringify(result, null, 2);

const text = $json.output ?? $json.message?.text ?? $json.text ?? '';
if (text.length > 1000000) throw new Error("Input is too large");
const fencedRe = /``````/gi;
const fencedMatches = Array.from(text.matchAll(fencedRe));
const fenced = [];
for (const match of fencedMatches) {
  const block = match[1].trim();
  if (!block || block === '{}') continue;
  try { fenced.push(JSON.parse(block)); } catch (e) { continue; }
}
const extractJsonObjects = (str) => {
  const results = [];
  let stack = 0, start = -1;
  let inString = false, esc = false;
  for (let i = 0; i < str.length; i++) {
    const ch = str[i];
    if (inString) { if (esc) { esc = false; continue; } if (ch === '\\') { esc = true; continue; } if (ch === '"') { inString = false; continue; } }
    if (ch === '"') { inString = true; continue; }
    if (ch === '{') { if (stack === 0) start = i; stack++; continue; }
    if (ch === '}') { if (stack > 0) stack--; if (stack === 0 && start !== -1) { try { results.push(JSON.parse(str.slice(start, i + 1))); } catch {} start = -1; } }
  }
  return results;
};
const unfenced = extractJsonObjects(text);
const all = [...fenced, ...unfenced];
const payload = all.reduce((acc, obj) => Object.assign(acc, obj), {});
const flags = { move_lead: !!payload.move_lead, escalate_to_manager: !!payload.escalate_to_manager };
// === Логирование токенов ===
const outputLength = (text || '').length;
const estimatedTokens = Math.ceil(outputLength / 4);
console.log(`[TOKENS] output_chars=${outputLength} est_tokens=${estimatedTokens}`);
// === A16: Мониторинг токенов ===
const rawOutputLength = (text || '').length;
const estimatedInputTokens = Math.ceil(rawOutputLength / 4);
const estimatedOutputTokens = Math.ceil((text || '').length / 4);
const timestamp = new Date().toISOString();

// Логируем в консоль n8n
console.log(JSON.stringify({
  event: 'TOKEN_USAGE',
  timestamp: timestamp,
  output_chars: rawOutputLength,
  est_output_tokens: estimatedOutputTokens,
  has_escalation: !!(payload?.escalate_to_manager || payload?.move_lead || flags?.escalate_to_manager || flags?.move_lead),
  escalation_type: payload?.escalation_type || 'none'
}));
return { raw_output: text, payload, flags };

// Получаем origin из Bitrix24
let origin = '';
try {
  origin = $('Normalize_b24').first().json.origin || 'bitrix24';
} catch (e) {
  origin = 'bitrix24';
}

// Для Битрикс — все каналы через Открытые Линии = чистый текст без HTML
// Telegram через Б24 не поддерживает HTML-разметку в im.message.add
const isBitrix = true;
const isWhatsApp = false;
const isVK = false;
const isInstagram = false;
const isAvito = false;
const isTelegram = origin === 'openline' || origin === 'bitrix24';

const text = $input.item.json.user_message_text || '';

let result = text;

// ========== ОБЩАЯ ОЧИСТКА (Markdown → убираем) ==========
result = result.replace(/\*\*(.+?)\*\*/g, '$1');
result = result.replace(/__(.+?)__/g, '$1');
result = result.replace(/(?<!\*)\*(?!\*)(.+?)(?<!\*)\*(?!\*)/g, '$1');
result = result.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1 ($2)');
result = result.replace(/`([^`]+)`/g, '$1');
result = result.replace(/^#{1,6}\s+/gm, '');
result = result.replace(/^[\-\*\_]{3,}\s*$/gm, '');
result = result.replace(/^[\-\*]\s+/gm, '• ');
result = result.replace(/```(?:json)?\s*\n?([\s\S]*?)```/g, '$1');

// ========== HTML → чистый текст (Б24 im.message.add поддерживает BB-коды, не HTML) ==========

// Ссылки
result = result.replace(/<a\s+href="([^"]+)"[^>]*>([^<]+)<\/a>/gi, '$2 ($1)');

// Bold → [B]text[/B] (BB-код для Битрикс)
result = result.replace(/<b>(.*?)<\/b>/gi, '[B]$1[/B]');
result = result.replace(/<strong>(.*?)<\/strong>/gi, '[B]$1[/B]');

// Italic
result = result.replace(/<i>(.*?)<\/i>/gi, '[I]$1[/I]');
result = result.replace(/<em>(.*?)<\/em>/gi, '[I]$1[/I]');

// Остальные HTML теги — убираем
result = result.replace(/<br\s*\/?>/gi, '\n');
result = result.replace(/<\/p>/gi, '\n\n');
result = result.replace(/<p>/gi, '');
result = result.replace(/<li>(.*?)<\/li>/gi, '• $1\n');
result = result.replace(/<\/?ul>/gi, '');
result = result.replace(/<\/?ol>/gi, '');
result = result.replace(/<\/?code>/gi, '');
result = result.replace(/<[^>]+>/g, '');

// HTML entities
result = result.replace(/&nbsp;/g, ' ');
result = result.replace(/&amp;/g, '&');
result = result.replace(/&lt;/g, '<');
result = result.replace(/&gt;/g, '>');
result = result.replace(/&quot;/g, '"');
result = result.replace(/&#39;/g, "'");
result = result.replace(/&#x27;/g, "'");
result = result.replace(/&mdash;/g, '—');
result = result.replace(/&ndash;/g, '–');
result = result.replace(/&raquo;/g, '»');
result = result.replace(/&laquo;/g, '«');

// Очистка
result = result.replace(/\n{3,}/g, '\n\n');
result = result.replace(/  +/g, ' ');
// === A15: Фильтрация битых ссылок ===
// Убираем ссылки на товары которые могут быть удалены (404)
// Оставляем только ссылки на gadget-bar.ru если они корректные
result = result.replace(/https?:\/\/gadget-bar\.ru\/product\/[^\s)\]]+/g, (url) => {
  // Если ссылка содержит oid= — это конкретный товар, оставляем
  if (url.includes('oid=')) return url;
  // Если нет oid — возможно битая, убираем
  return '';
});
// Убираем двойные пробелы после удаления ссылок
result = result.replace(/  +/g, ' ');
result = result.trim();

// === A12: Логирование качества ===
const hasMarkdown = /\*\*|__|##|```/.test(result);
const hasHtml = /<[a-zA-Z\/][^>]*>/.test(result);
const hasSpecial = /[\x00-\x08\x0B\x0C\x0E-\x1F]/.test(result);
if (hasMarkdown || hasHtml || hasSpecial) {
  console.log(JSON.stringify({
    event: 'QUALITY_ISSUE',
    has_markdown: hasMarkdown,
    has_html: hasHtml,
    has_special: hasSpecial,
    text_preview: result.substring(0, 200)
  }));
}

return {
  json: {
    formatted_text: result,
    is_whatsapp: isWhatsApp,
    is_vk: isVK,
    is_instagram: isInstagram,
    is_avito: isAvito,
    is_telegram: isTelegram,
    is_bitrix: isBitrix,
    user_message_text: text,
    json_payload: $input.item.json.json_payload,
    origin: origin
  }
};

// === Normalize Bitrix24 → Telegram-like ===
const body = $('Webhook_b24').first().json.body || {};

// Extract params
const getParam = (key) => body['data[PARAMS][' + key + ']'] || '';
const getUser = (key) => body['data[USER][' + key + ']'] || '';
const getBot = (key) => body['data[BOT][3922][' + key + ']'] || '';
const getAuth = (key) => body['auth[' + key + ']'] || '';

const text = getParam('MESSAGE') || '';
const dialogId = getParam('DIALOG_ID') || '';
const toChatId = getParam('TO_CHAT_ID') || '';
const fromUserId = getParam('FROM_USER_ID') || '';
const messageId = getParam('MESSAGE_ID') || '';
const chatType = getParam('CHAT_TYPE') || '';
const messageType = getParam('MESSAGE_TYPE') || '';
// CRM lead id from Open Lines entity data, e.g. "LEAD|10954|COMPANY|0|..."
const entityData2 = getParam('CHAT_ENTITY_DATA_2') || '';
const ed2Parts = entityData2.split('|');
const leadId = (ed2Parts[0] === 'LEAD' && ed2Parts[1]) ? ed2Parts[1] : '';

// Access token for API calls (Bitrix sends fresh token with every event)
const accessToken = getAuth('access_token') || getBot('access_token') || '';
const refreshToken = getAuth('refresh_token') || getBot('refresh_token') || '';

const userName = getUser('NAME') || 'Клиент';
const userFirstName = getUser('FIRST_NAME') || '';
const userId = getUser('ID') || '';
const isBot = getUser('IS_BOT') === 'Y';
const isConnector = getUser('IS_CONNECTOR') === 'Y';
// Проверка: сообщение от оператора (менеджера) или от клиента
const isOperator = getParam('CHAT_ENTITY_TYPE') === 'LINES' && !isConnector && !isBot;
const messageFrom = getParam('FROM_USER_TYPE') || '';
const isFromOperator = messageFrom === 'operator' || (!isConnector && !isBot && chatType !== 'L');

// Determine origin for text formatter
let origin = 'bitrix24';
if (chatType === 'L') origin = 'openline';

// Build Telegram-like message object (compatible with existing pipeline)
const msg = {
  text: text || '',
  chat: { id: 'b24_' + (toChatId || dialogId) },
  entities: [],
  voice: undefined,
  photo: undefined,
  document: undefined,
};

// Handle /start
if ((msg.text || '').startsWith('/start')) {
  msg.entities.push({ type: 'bot_command', offset: 0, length: 6 });
}

return {
  json: {
    message: msg,
    b24_dialog_id: dialogId,
    b24_lead_id: leadId,
    b24_chat_id: toChatId,
    b24_from_user_id: fromUserId,
    b24_message_id: messageId,
    b24_chat_type: chatType,
    b24_user_name: userName,
    b24_user_id: userId,
    b24_is_bot: isBot,
    b24_is_connector: isConnector,
    b24_access_token: accessToken,
    b24_refresh_token: refreshToken,
    origin: origin,
    raw_event: body.event || 'unknown',
    b24_is_operator: isFromOperator
  }
};

// --- Code2 for Bitrix24 (Redis buffer merge) ---

const chatId = $('Normalize_b24').first().json.message?.chat?.id ?? null;

if (!chatId) {
  const errorMsg = "FATAL: Could not determine chatId.";
  return [{ json: { message: { text: JSON.stringify({ user_query:'', context_message:'', error: errorMsg }) } } }];
}

const key = `user:${chatId}:buffer`;
let redis;

try {
  const Redis = require('ioredis');
  redis = new Redis({
    host: 'redis',
    port: 6379,
    db:   0,
    lazyConnect: true,
    connectTimeout: 2000,
    maxRetriesPerRequest: 1,
    enableReadyCheck: false,
  });

  await Promise.race([
    redis.connect(),
    new Promise((_, reject) => setTimeout(() => reject(new Error('Redis connection timed out')), 2200)),
  ]);

  const res = await redis.multi().lrange(key, 0, -1).del(key).exec();
  const buffer = Array.isArray(res?.[0]?.[1]) ? res[0][1] : [];

  if (buffer.length === 0) {
      return [{ json: { message: { text: JSON.stringify({ user_query:'', context_message:'', info: 'Buffer was empty.' }) } } }];
  }

  const allMessages = buffer.map(r => { try { return JSON.parse(r); } catch { return null; } }).filter(Boolean);

  const combined_user_query = allMessages
    .map(msg => (msg.user_query ?? msg.user_caption ?? '').trim())
    .filter(Boolean)
    .join(' ');

  const first_context_message = allMessages[0]?.context_message ?? '';

  const out = {
    user_query: combined_user_query,
    context_message: first_context_message
  };

  return [{ json: { message: { text: JSON.stringify(out, null, 2) } } }];

} catch (e) {
  const errorMessage = String(e?.message || e);
  return [{ json: { message: { text: JSON.stringify({ user_query:'', context_message:'', error: errorMessage, key_used: key }) } } }];
} finally {
  if (redis?.status === 'ready') {
    try {
      await Promise.race([redis.quit(), new Promise(r => setTimeout(r, 400))]);
    } catch {}
  }
}

// === Code Conversation for Bitrix24 ===
// Parses im.dialog.messages.get response

const rawResult = $input.item.json;
const result = rawResult?.result || rawResult;
const messages = result?.messages || [];

const BOT_ID = 3922;

const stripHtml = (s = '') => {
  if (!s) return '';
  s = s.replace(/<a\s+href=\"([^\"]+)\"[^>]*>(.*?)<\/a>/gis, (_, u, t) => `${t} (${u})`);
  s = s.replace(/<br\s*\/?>/gi, '\n');
  s = s.replace(/<\/p>/gi, '\n\n').replace(/<p>/gi, '');
  s = s.replace(/<\/?(b|strong|i|em)>/gi, '');
  s = s.replace(/<\/?code>/gi, '`');
  s = s.replace(/<[^>]+>/g, '');
  s = s.replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/&lt;/g, '<').replace(/&gt;/g, '>').replace(/&quot;/g, '"');
  return s.replace(/\n{3,}/g, '\n\n').trim();
};

const now = Math.floor(Date.now() / 1000);
const ONE_WEEK_SEC = 7 * 24 * 60 * 60;

// Messages from B24 API: { id, text, date, author_id, ... }
const msgs = messages
  .filter(m => {
    const msgTime = m.date ? Math.floor(new Date(m.date).getTime() / 1000) : 0;
    return (now - msgTime) <= ONE_WEEK_SEC;
  })
  .sort((a, b) => new Date(a.date || 0) - new Date(b.date || 0));

const pairs = [];
let currentPair = null;

for (const m of msgs) {
  const text = stripHtml(m.text || '');
  if (!text) continue;

  const authorId = Number(m.author_id || 0);
  const isFromClient = authorId !== BOT_ID && authorId > 0;

  if (isFromClient) {
    if (!currentPair) {
      currentPair = { q: text, a: [], qTime: m.date || '' };
    } else if (currentPair.a.length === 0) {
      currentPair.q += '\n' + text;
    } else {
      pairs.push(currentPair);
      currentPair = { q: text, a: [], qTime: m.date || '' };
    }
  } else {
    if (currentPair) {
      currentPair.a.push(text);
    }
  }
}
if (currentPair) pairs.push(currentPair);

const recent = pairs.slice(-6);
const qa_md = recent.map((p, i) => {
  const n = i + 1;
  return `**Вопрос ${n} (${p.qTime}):** ${p.q}\n**Ответ ${n}:** ${p.a.join('\n') || '(нет ответа)'}`;
}).join('\n\n');

const userName = $('Normalize_b24').first().json.b24_user_name || 'Клиент';

return { json: { qa_md, client_label: userName, client_name: userName } };

