// === Escalation Router ===
// Разбирает тип эскалации и готовит данные для API вызовов

const payload = $json.payload || {};
const flags = $json.flags || {};
const rawOutput = $json.raw_output || '';

const escalationType = payload.escalation_type || (flags.escalate_to_manager ? 'human_request' : 'none');
const dealStage = payload.deal_stage || payload.status_name || 'NEW';
const taskText = payload.task_text || 'Запрос от бота';
const noPurchase = payload.no_purchase || false;
const summary = payload.summary || '';

const accessToken = $('Normalize_b24').first().json.b24_access_token || '';
const userName = $('Normalize_b24').first().json.b24_user_name || 'Клиент';
let clientText = rawOutput.split('```')[0].trim();
clientText = clientText.replace(/\{[\s"]*(?:move_lead|escalate_to_manager|dialog_complete|no_purchase)[\s\S]*?\}/g, '').trim();

const ECOMMERCE_MANAGER_ID = 420;

// === A10: Логирование в bot_action_log ===
// Будет записано через HTTP Request ноду после
const logData = {
  action_type: 'escalation',
  escalation_type: escalationType,
  deal_stage: dealStage,
  user_name: userName
};

return {
  json: {
    escalation_type: escalationType,
    deal_stage: dealStage,
    log_data: logData,
    task_text: taskText + ' (Клиент: ' + userName + ')',
    no_purchase: noPurchase,
    summary: summary,
    client_text: clientText,
    access_token: accessToken,
    ecommerce_manager_id: ECOMMERCE_MANAGER_ID,
    move_lead: flags.move_lead || payload.move_lead || false,
    escalate: flags.escalate_to_manager || payload.escalate_to_manager || false,
    formatted_text: clientText
  }
};

